callGraph.callee:
(() => {
				// The disk read always returns the whole file, so report 1–N
				const lineCount = fileContent.trimEnd().split("\n").length;
				return `1–${lineCount}`;
			})

value
		.map((item): QuestionToolQuestion | null => {
			if (typeof item !== "object" || item === null) return null;
			const record = item as Record<string, unknown>;
			const question =
				typeof record.question === "string" ? record.question.trim() : "";
			if (!question) return null;

			const options = Array.isArray(record.options)
				? record.options
						.map((option): QuestionToolOption | null => {
							if (typeof option !== "object" || option === null) return null;
							const optionRecord = option as Record<string, unknown>;
							const label =
								typeof optionRecord.label === "string"
									? optionRecord.label.trim()
									: "";
							if (!label) return null;
							const description =
								typeof optionRecord.description === "string"
									? optionRecord.description.trim()
									: "";
							return description ? { label, description } : { label };
						})
						.filter((option): option is QuestionToolOption => option !== null)
				: [];

			const header =
				typeof record.header === "string" ? record.header.trim() : "";
			const multiSelect =
				typeof record.multiSelect === "boolean"
					? record.multiSelect
					: undefined;

			return {
				question,
				...(header ? { header } : {}),
				options,
				...(multiSelect === undefined ? {} : { multiSelect }),
			};
		})
		.filter

record.options
						.map((option): QuestionToolOption | null => {
							if (typeof option !== "object" || option === null) return null;
							const optionRecord = option as Record<string, unknown>;
							const label =
								typeof optionRecord.label === "string"
									? optionRecord.label.trim()
									: "";
							if (!label) return null;
							const description =
								typeof optionRecord.description === "string"
									? optionRecord.description.trim()
									: "";
							return description ? { label, description } : { label };
						})
						.filter

args.options
				.map((opt): QuestionToolOption | null => {
					if (typeof opt !== "object" || opt === null) return null;
					const o = opt as Record<string, unknown>;
					const label = typeof o.label === "string" ? o.label.trim() : "";
					if (!label) return null;
					const description =
						typeof o.description === "string" ? o.description.trim() : "";
					return description ? { label, description } : { label };
				})
				.filter

questions
				.map((q) => ({
					question: q.question,
					answer: findAnswerForQuestion({ answers, questionText: q.question }),
				}))
				.filter

params:
{
	part,
	toolName,
	subtitle,
	icon: Icon = WrenchIcon,
}
